#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char logo[3][4];
        for (int i = 0; i < 3; i++) {
            scanf("%s", logo[i]);
        }
        int good = 0;
        for (int i = 0; i < 2; i++) {
            for (int j = 0; j < 2; j++) {
                if (logo[i][j] == 'l' && logo[i+1][j] == 'l' && logo[i+1][j+1] == 'l') {
                    good = 1;
                }
            }
        }
        if (good) printf("yes\n");
        else printf("no\n");
    }
    return 0;
}

