code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            char[][] logo = new char[3][3];
            for (int i = 0; i < 3; i++) {
                String s = sc.next();
                for (int j = 0; j < 3; j++) {
                    logo[i][j] = s.charAt(j);
                }
            }
            boolean good = false;
            for (int i = 0; i < 2; i++) {
                for (int j = 0; j < 2; j++) {
                    if (logo[i][j] == 'l' && logo[i+1][j] == 'l' && logo[i+1][j+1] == 'l') {
                        good = true;
                    }
                }
            }
            if (good) System.out.println("yes");
            else System.out.println("no");
        }
    }
}

